# ALGORITHM CONFUSION ATTACK TESTS (SEC-081 Evidence Requirement)
# =============================================================================

class TestAlgorithmConfusionPrevention:
    """
    Tests for CVE-2015-9235 algorithm confusion attack prevention.

    Attack Vector:
    1. Attacker obtains public key (often exposed in JWKS endpoint)
    2. Attacker creates HS256 token using public key as HMAC secret
    3. Vulnerable servers accept token if they use public key for verification

    Expected Behavior:
    - TokenService MUST reject HS256 tokens
    - TokenService MUST reject "none" algorithm tokens
    - TokenService MUST only accept RS256 tokens
    """

    def test_rejects_hs256_token_signed_with_public_key(self, rsa_keypair, token_service):
        """
        CRITICAL TEST: Verify algorithm confusion attack is blocked.

        This test creates an HS256 token using a regular secret and
        verifies that TokenService rejects it (even if signature is valid
        for HS256, we only accept RS256).

        Note: Modern PyJWT prevents using RSA keys as HMAC secrets,
        so we test that ANY HS256 token is rejected regardless of secret.
        """
        # Create HS256 token with a regular secret
        claims = {
            "iss": ISSUER,
            "aud": AUDIENCES,
            "sub": str(uuid4()),
            "org_id": str(uuid4()),
            "exp": int((datetime.utcnow() + timedelta(hours=1)).timestamp()),
            "iat": int(datetime.utcnow().timestamp()),
            "jti": "attack_token_123",
            "type": "access",
        }

        # Sign with HS256 using any secret (simulating attack where
        # attacker tries to use HS256 instead of RS256)
        malicious_token = jwt.encode(
            claims,
            "any-secret-key",  # Attacker's secret
            algorithm="HS256"
        )

        # TokenService MUST reject this token because it's HS256
        with pytest.raises(InvalidAlgorithmError) as exc_info:
            token_service.verify(malicious_token)

        assert "HS256" in str(exc_info.value) or "blocked" in str(exc_info.value).lower()
        print(f"✅ HS256 token BLOCKED (only RS256 allowed): {exc_info.value}")

    def test_rejects_none_algorithm_token(self, token_service):
        """
        CRITICAL TEST: Verify "none" algorithm is blocked.

        The "none" algorithm attack allows tokens without signatures.
        TokenService MUST reject all tokens with "none" algorithm.
        """
        # Create unsigned token with "none" algorithm
        # We have to manually construct this since PyJWT blocks it
        import base64
        import json

        header = base64.urlsafe_b64encode(
            json.dumps({"alg": "none", "typ": "JWT"}).encode()
        ).rstrip(b"=").decode()

        claims = {
            "iss": ISSUER,
            "aud": AUDIENCES,
            "sub": str(uuid4()),
            "org_id": str(uuid4()),
            "exp": int((datetime.utcnow() + timedelta(hours=1)).timestamp()),
            "iat": int(datetime.utcnow().timestamp()),
            "jti": "none_attack_123",
            "type": "access",
        }

        payload = base64.urlsafe_b64encode(
            json.dumps(claims).encode()
        ).rstrip(b"=").decode()

        # Token with empty signature
        none_token = f"{header}.{payload}."

        # TokenService MUST reject this token
        with pytest.raises(InvalidAlgorithmError) as exc_info:
            token_service.verify(none_token)

        assert "none" in str(exc_info.value).lower() or "blocked" in str(exc_info.value).lower()
        print(f"✅ 'none' algorithm attack BLOCKED: {exc_info.value}")

    def test_accepts_valid_rs256_token(self, token_service):
        """
        Verify valid RS256 tokens are accepted.
        """
        user_id = uuid4()
        org_id = uuid4()

        # Create valid RS256 token
        token = token_service.create_access_token(
            user_id=user_id,
            org_id=org_id,
            role="admin",
            permissions=["read", "write"],
        )

        # Verify token
        context = token_service.verify(token)

        assert context.user_id == user_id
        assert context.org_id == org_id
        assert context.role == "admin"
        assert "read" in context.permissions
        print(f"✅ Valid RS256 token accepted: jti={context.token_jti}")

    def test_blocked_algorithms_list(self):
        """Verify all dangerous algorithms are in blocked list."""
        dangerous = ["none", "None", "NONE", "", "HS256", "HS384", "HS512"]
        for alg in dangerous:
            assert alg in BLOCKED_ALGORITHMS, f"Algorithm '{alg}' should be blocked"
        print(f"✅ All dangerous algorithms blocked: {dangerous}")


