# BCRYPT TO ARGON2ID MIGRATION TESTS (SEC-081 Evidence Requirement)
# =============================================================================

class TestPasswordMigration:
    """
    Tests for bcrypt → Argon2id password migration.

    The PasswordService must:
    1. Verify legacy bcrypt hashes
    2. Detect bcrypt hashes as needing rehash
    3. Transparently upgrade to Argon2id on verify
    """

    def test_hashes_with_argon2id(self, password_service):
        """Verify new passwords are hashed with Argon2id."""
        password = "SecurePassword123!"
        hashed = password_service.hash(password)

        assert hashed.startswith("$argon2id$"), f"Expected Argon2id hash, got: {hashed[:20]}"
        print(f"✅ Password hashed with Argon2id: {hashed[:40]}...")

    def test_verifies_argon2id_hash(self, password_service):
        """Verify Argon2id hashes can be verified."""
        password = "MySecretPassword456!"
        hashed = password_service.hash(password)

        assert password_service.verify(password, hashed)
        assert not password_service.verify("WrongPassword", hashed)
        print("✅ Argon2id verification working correctly")

    def test_detects_bcrypt_needs_rehash(self, password_service):
        """Verify bcrypt hashes are detected as needing rehash."""
        try:
            import bcrypt
        except ImportError:
            pytest.skip("bcrypt not installed")

        # Create legacy bcrypt hash
        password = "LegacyPassword789!"
        bcrypt_hash = bcrypt.hashpw(
            password.encode("utf-8"),
            bcrypt.gensalt(rounds=12)
        ).decode("utf-8")

        # Should detect as needing rehash
        assert password_service.needs_rehash(bcrypt_hash)
        print(f"✅ bcrypt hash detected as needing rehash: {bcrypt_hash[:20]}...")

    def test_verifies_legacy_bcrypt_direct(self, password_service):
        """Verify direct bcrypt hashes (core/security.py pattern)."""
        try:
            import bcrypt
        except ImportError:
            pytest.skip("bcrypt not installed")

        password = "DirectBcryptPassword!"
        bcrypt_hash = bcrypt.hashpw(
            password.encode("utf-8"),
            bcrypt.gensalt(rounds=12)
        ).decode("utf-8")

        assert password_service.verify(password, bcrypt_hash)
        print("✅ Direct bcrypt hash verified successfully")

    def test_verifies_legacy_sha256_bcrypt(self, password_service):
        """Verify SHA-256+bcrypt hashes (auth_utils.py pattern)."""
        try:
            import bcrypt
        except ImportError:
            pytest.skip("bcrypt not installed")

        password = "SHA256BcryptPassword!"

        # Create SHA-256 + bcrypt hash (legacy pattern)
        sha_digest = hashlib.sha256(password.encode("utf-8")).hexdigest()
        bcrypt_hash = bcrypt.hashpw(
            sha_digest.encode("utf-8"),
            bcrypt.gensalt(rounds=12)
        ).decode("utf-8")

        assert password_service.verify(password, bcrypt_hash)
        print("✅ SHA-256+bcrypt hash verified successfully")

    def test_verify_and_upgrade_returns_new_hash(self, password_service):
        """Verify verify_and_upgrade returns new Argon2id hash for bcrypt."""
        try:
            import bcrypt
        except ImportError:
            pytest.skip("bcrypt not installed")

        password = "UpgradeMe123!"

        # Create legacy bcrypt hash
        bcrypt_hash = bcrypt.hashpw(
            password.encode("utf-8"),
            bcrypt.gensalt(rounds=12)
        ).decode("utf-8")

        # Verify and upgrade
        is_valid, new_hash = password_service.verify_and_upgrade(password, bcrypt_hash)

        assert is_valid, "Password should be valid"
        assert new_hash is not None, "New hash should be returned"
        assert new_hash.startswith("$argon2id$"), "New hash should be Argon2id"
        print(f"✅ Password upgraded: bcrypt → Argon2id")
        print(f"   Old: {bcrypt_hash[:30]}...")
        print(f"   New: {new_hash[:40]}...")


