class TestTenantContext:
    """Tests for immutable TenantContext."""

    def test_context_is_immutable(self):
        """Verify TenantContext cannot be modified after creation."""
        context = TenantContext(
            org_id=uuid4(),
            tenant_id="acme-corp",
            user_id=uuid4(),
            role="admin",
            permissions=frozenset(["read", "write"]),
            session_id="sess_123",
            token_jti="tok_456",
            authenticated_at=datetime.utcnow().timestamp(),
            token_expires_at=(datetime.utcnow() + timedelta(hours=1)).timestamp(),
        )

        # Attempting to modify should raise FrozenInstanceError
        with pytest.raises(Exception):  # dataclass FrozenInstanceError
            context.role = "user"

        print("✅ TenantContext is immutable")

    def test_context_from_claims(self):
        """Test creating TenantContext from JWT claims."""
        org_id = uuid4()
        user_id = uuid4()

        claims = {
            "sub": str(user_id),
            "org_id": str(org_id),
            "tenant_id": "test-tenant",
            "role": "admin",
            "permissions": ["read", "write", "admin"],
            "session_id": "sess_test",
            "jti": "tok_test",
            "iat": int(datetime.utcnow().timestamp()),
            "exp": int((datetime.utcnow() + timedelta(hours=1)).timestamp()),
        }

        context = TenantContext.from_claims(claims)

        assert context.org_id == org_id
        assert context.user_id == user_id
        assert context.role == "admin"
        assert "write" in context.permissions
        print("✅ TenantContext.from_claims() working correctly")

    def test_org_id_is_uuid(self, token_service):
        """Verify org_id in TenantContext is UUID type."""
        token = token_service.create_access_token(
            user_id=uuid4(),
            org_id=uuid4(),
            role="user",
        )

        context = token_service.verify(token)

        assert isinstance(context.org_id, UUID), f"org_id should be UUID, got {type(context.org_id)}"
        print(f"✅ org_id is UUID type: {context.org_id}")


