class TestTokenRevocation:
    """Tests for token revocation functionality."""

    def test_revoked_token_is_rejected(self, token_service):
        """Verify revoked tokens are rejected."""
        user_id = uuid4()
        org_id = uuid4()

        # Create token
        token = token_service.create_access_token(
            user_id=user_id,
            org_id=org_id,
            role="user",
        )

        # Verify token works
        context = token_service.verify(token)
        assert context.user_id == user_id

        # Revoke token
        token_service.revoke(token)

        # Token should now be rejected
        from services.unified_auth.exceptions import TokenRevokedError
        with pytest.raises(TokenRevokedError):
            token_service.verify(token)

        print("✅ Revoked token rejected successfully")


