class TestPasswordPepper:
    """Tests for password pepper defense-in-depth."""

    def test_pepper_changes_hash(self):
        """Verify pepper produces different hash than no pepper."""
        # Import fresh to avoid caching
        import importlib
        import services.password_service as ps_module

        # Clear AWS credentials to force local-only mode
        aws_vars = ["AWS_ACCESS_KEY_ID", "AWS_SECRET_ACCESS_KEY", "AWS_SESSION_TOKEN"]
        saved_aws = {k: os.environ.pop(k, None) for k in aws_vars}

        try:
            importlib.reload(ps_module)

            # Without pepper
            os.environ["ENVIRONMENT"] = "development"
            if "ASCEND_AUTH_PASSWORD_PEPPER" in os.environ:
                del os.environ["ASCEND_AUTH_PASSWORD_PEPPER"]

            importlib.reload(ps_module)
            service_no_pepper = ps_module.PasswordService()
            pepper_1 = service_no_pepper._pepper

            # With pepper
            os.environ["ASCEND_AUTH_PASSWORD_PEPPER"] = "my-secret-pepper"
            importlib.reload(ps_module)
            service_with_pepper = ps_module.PasswordService()
            pepper_2 = service_with_pepper._pepper

            # Verify pepper is being used by checking the service state
            assert pepper_1 is None, f"Expected no pepper, got: {pepper_1}"
            assert pepper_2 == "my-secret-pepper", f"Expected pepper, got: {pepper_2}"
            print("✅ Pepper configuration verified")

        finally:
            # Restore AWS credentials
            for k, v in saved_aws.items():
                if v is not None:
                    os.environ[k] = v

    def test_hash_without_pepper_fails_with_pepper(self):
        """Verify hash created without pepper cannot be verified with pepper."""
        # Import fresh to avoid caching
        import importlib
        import services.password_service as ps_module

        # Clear AWS credentials to force local-only mode
        aws_vars = ["AWS_ACCESS_KEY_ID", "AWS_SECRET_ACCESS_KEY", "AWS_SESSION_TOKEN"]
        saved_aws = {k: os.environ.pop(k, None) for k in aws_vars}

        try:
            password = "TestPassword456!"

            # Create hash without pepper
            os.environ["ENVIRONMENT"] = "development"
            if "ASCEND_AUTH_PASSWORD_PEPPER" in os.environ:
                del os.environ["ASCEND_AUTH_PASSWORD_PEPPER"]

            importlib.reload(ps_module)
            service_no_pepper = ps_module.PasswordService()
            hash_no_pepper = service_no_pepper.hash(password)

            # Try to verify with pepper (should fail)
            os.environ["ASCEND_AUTH_PASSWORD_PEPPER"] = "different-pepper"
            importlib.reload(ps_module)
            service_with_pepper = ps_module.PasswordService()

            # Verification should fail because pepper changes the input
            is_valid = service_with_pepper.verify(password, hash_no_pepper)
            assert not is_valid, "Hash without pepper should not verify with pepper"
            print("✅ Pepper provides defense-in-depth protection")

        finally:
            # Restore AWS credentials
            for k, v in saved_aws.items():
                if v is not None:
                    os.environ[k] = v


